import type { ColumnDef, Row } from "@tanstack/react-table"
import type * as React from "react"

/** Stable id for the synthesized auto group column. */
export const GROUP_COLUMN_ID = "__group__" as const

/** A groupable column surfaced in the dimension picker. */
export type DimensionDef = {
  /** Must match the `id` of a column in `columns`. */
  id: string
  /** Human-readable label shown in the picker. */
  label: string
}

/**
 * Declarative leaf rendering: a primary label, with an optional leading icon and
 * an optional muted secondary line below it. Each accessor returns whatever you
 * want to show (or you can omit `icon`/`secondary` entirely).
 */
export type GroupLeafConfig<TData> = {
  /** Main label for the leaf row. */
  primary: (row: Row<TData>) => React.ReactNode
  /** Optional muted line shown beneath the primary label. Omit to show none. */
  secondary?: (row: Row<TData>) => React.ReactNode
  /** Optional leading icon. Omit to show none. */
  icon?: (row: Row<TData>) => React.ReactNode
}

export type GroupColumnConfig<TData> = {
  /** Header text for the auto group column, e.g. "Account". */
  header?: React.ReactNode
  /**
   * Declarative leaf rendering (primary + optional icon/secondary). Use this for
   * the common case. Ignored if `renderLeaf` is provided.
   */
  leaf?: GroupLeafConfig<TData>
  /**
   * Full-control leaf renderer — return any node. Takes precedence over `leaf`.
   * Provide either `leaf` or `renderLeaf`; if neither is set, leaf rows render blank.
   */
  renderLeaf?: (row: Row<TData>) => React.ReactNode
  /**
   * How the `(count)` next to a group label is computed.
   * "leaf" = total leaf descendants (default), "immediate" = direct sub-rows.
   */
  countMode?: "leaf" | "immediate"
  /** Pixels of indentation per depth level. Default 24. */
  indentSize?: number
}

export type FilterType = "text" | "number" | "select" | "date"

export type FilterOperator =
  | "contains" | "doesNotContain" | "equals" | "isNot" | "startsWith"
  | "eq" | "ne" | "gt" | "lt" | "between"
  | "is" | "isAnyOf" | "isNoneOf"
  | "before" | "after" | "dateBetween"

export type FilterDef = {
  /**
   * Must match a column's `id`/`accessorKey` AND a key on the row data — the
   * filter engine reads the value via `row[id]`. Filterable columns must
   * therefore be accessorKey-based (not `accessorFn`-only).
   */
  id: string
  label: string
  type: FilterType
  /** Allowed operators; falls back to the type default when omitted. */
  operators?: FilterOperator[]
  /** Required for type "select" — the choosable values. */
  options?: { label: string; value: string }[]
}

export type FilterValue =
  | string
  | number
  | [number, number]
  | [string, string]
  | string[]
  | null

export type FilterCondition = {
  /** Unique id for keying / removal. */
  id: string
  columnId: string
  operator: FilterOperator
  value: FilterValue
}

export type Combinator = "and" | "or"
export type FilterGroup = { id: string; combinator: Combinator; conditions: FilterCondition[] }
export type FilterState = { combinator: Combinator; groups: FilterGroup[] }

export type GroupedDataTableProps<TData> = {
  data: TData[]
  /** Measure / attribute columns. Groupable columns must set `enableGrouping: true`. */
  columns: ColumnDef<TData, unknown>[]
  /** Which columns the developer allows grouping on. */
  groupableDimensions: DimensionDef[]
  groupColumn: GroupColumnConfig<TData>
  /**
   * Initial hierarchy order, e.g. ["entity", "bank"]. Applied once at mount;
   * later changes to this prop are ignored (use the returned `setGrouping` to
   * change grouping after mount).
   */
  initialGrouping?: string[]
  /** Enable client-side pagination. Default true. */
  enablePagination?: boolean
  /** Declares which columns are filterable and how (the filter "options"). */
  filterableColumns?: FilterDef[]
  /** Initial filter state (groups + AND/OR). */
  initialFilterState?: FilterState
}

import type { Row, VisibilityState } from "@tanstack/react-table"

import type { GroupColumnConfig } from "./types"

/**
 * Count shown next to a group label.
 *
 * "leaf" (default) counts the underlying DATA records in the group. TanStack's
 * `row.getLeafRows()` flattens the whole subtree and includes intermediate
 * grouped rows (e.g. nested bank groups), so those are filtered out to count
 * only real records. "immediate" counts direct sub-rows (groups or records).
 */
export function getGroupRowCount<TData>(
  row: Row<TData>,
  countMode: GroupColumnConfig<TData>["countMode"] = "leaf",
): number {
  return countMode === "immediate"
    ? row.subRows.length
    : row.getLeafRows().filter((leaf) => !leaf.getIsGrouped()).length
}

/** Keep only allowed ids, preserve order, dedupe. */
export function normalizeGrouping(
  grouping: string[],
  allowedIds: string[],
): string[] {
  const allowed = new Set(allowedIds)
  const seen = new Set<string>()
  const result: string[] = []
  for (const id of grouping) {
    if (allowed.has(id) && !seen.has(id)) {
      seen.add(id)
      result.push(id)
    }
  }
  return result
}

/**
 * Hide dimension columns that are currently part of the grouping. Only grouped
 * ids are returned (mapped to `false`); absent keys fall back to TanStack's
 * default of visible, so ungrouping a column re-shows it automatically.
 */
export function deriveColumnVisibility(grouping: string[]): VisibilityState {
  const visibility: VisibilityState = {}
  for (const id of grouping) {
    visibility[id] = false
  }
  return visibility
}

import type {
  Combinator,
  FilterCondition,
  FilterDef,
  FilterGroup,
  FilterOperator,
  FilterState,
  FilterType,
  FilterValue,
} from "./types"

const DEFAULT_OPERATORS: Record<FilterType, FilterOperator[]> = {
  text: ["contains", "doesNotContain", "equals", "isNot", "startsWith"],
  number: ["eq", "ne", "gt", "lt", "between"],
  select: ["isAnyOf", "isNoneOf", "is"],
  date: ["before", "after", "dateBetween"],
}

export const OPERATOR_LABELS: Record<FilterOperator, string> = {
  contains: "contains",
  doesNotContain: "does not contain",
  equals: "is",
  isNot: "is not",
  startsWith: "starts with",
  eq: "equals",
  ne: "not equal",
  gt: "greater than",
  lt: "less than",
  between: "between",
  is: "is",
  isAnyOf: "is any of",
  isNoneOf: "is none of",
  before: "before",
  after: "after",
  dateBetween: "between",
}

export function defaultOperatorsFor(type: FilterType): FilterOperator[] {
  return DEFAULT_OPERATORS[type]
}

export function operatorsForDef(def: FilterDef): FilterOperator[] {
  return def.operators && def.operators.length > 0
    ? def.operators
    : defaultOperatorsFor(def.type)
}

function isEmpty(value: FilterValue): boolean {
  if (value == null) return true
  if (typeof value === "string") return value.trim() === ""
  if (Array.isArray(value)) {
    return value.length === 0 || value.every((v) => v == null || v === "")
  }
  return false
}

export function evaluateCondition(
  cellValue: unknown,
  operator: FilterOperator,
  value: FilterValue,
): boolean {
  if (isEmpty(value)) return true

  const text = String(cellValue ?? "").toLowerCase()
  switch (operator) {
    case "contains":
      return text.includes(String(value).toLowerCase())
    case "equals":
      return text === String(value).toLowerCase()
    case "startsWith":
      return text.startsWith(String(value).toLowerCase())
    case "eq":
      return Number(cellValue) === Number(value)
    case "ne":
      return Number(cellValue) !== Number(value)
    case "gt":
      return Number(cellValue) > Number(value)
    case "lt":
      return Number(cellValue) < Number(value)
    case "between": {
      // Guard: range operators need a [min, max] pair; a scalar mid-build
      // (e.g. only one bound entered) is treated as no constraint, not a crash.
      if (!Array.isArray(value)) return true
      const [min, max] = value as [number, number]
      // Either bound still blank (mid-build) → no constraint, so the table
      // doesn't go empty while the user is typing the first bound.
      if (String(min).trim() === "" || String(max).trim() === "") return true
      const n = Number(cellValue)
      return n >= Number(min) && n <= Number(max)
    }
    case "doesNotContain":
      return !text.includes(String(value).toLowerCase())
    case "isNot":
      return String(cellValue ?? "").toLowerCase() !== String(value).toLowerCase()
    case "isNoneOf":
      return !(value as string[]).map(String).includes(String(cellValue ?? ""))
    // `is`/`isAnyOf`/`isNoneOf` are case-sensitive by design: select columns hold
    // exact enum values (e.g. "HSBC"), unlike the case-insensitive text operators.
    case "is":
      return String(cellValue ?? "") === String(value)
    case "isAnyOf":
      return (value as string[]).map(String).includes(String(cellValue ?? ""))
    case "before":
      return new Date(String(cellValue)).getTime() < new Date(String(value)).getTime()
    case "after":
      return new Date(String(cellValue)).getTime() > new Date(String(value)).getTime()
    case "dateBetween": {
      if (!Array.isArray(value)) return true
      const [start, end] = value as string[]
      if (String(start).trim() === "" || String(end).trim() === "") return true
      const t = new Date(String(cellValue)).getTime()
      return t >= new Date(start).getTime() && t <= new Date(end).getTime()
    }
    default:
      return true
  }
}

export function describeCondition(
  condition: FilterCondition,
  def?: FilterDef,
): string {
  const label = def?.label ?? condition.columnId
  const op = OPERATOR_LABELS[condition.operator]
  const value = condition.value

  const labelFor = (raw: unknown): string =>
    def?.type === "select"
      ? (def.options?.find((o) => o.value === String(raw))?.label ?? String(raw))
      : String(raw)

  let valueStr: string
  if (Array.isArray(value)) {
    const sep =
      condition.operator === "between" || condition.operator === "dateBetween"
        ? "–"
        : ", "
    valueStr = value.map(labelFor).join(sep)
  } else if (value == null) {
    valueStr = ""
  } else {
    valueStr = labelFor(value)
  }
  return `${label} ${op} ${valueStr}`.trim()
}

export function createCondition(
  filterDefs: FilterDef[],
  id: string,
): FilterCondition {
  const def = filterDefs[0]
  if (!def) {
    throw new Error("createCondition: filterDefs must not be empty")
  }
  return { id, columnId: def.id, operator: operatorsForDef(def)[0], value: null }
}

export function withColumn(
  condition: FilterCondition,
  columnId: string,
  filterDefs: FilterDef[],
): FilterCondition {
  const def = filterDefs.find((d) => d.id === columnId) ?? filterDefs[0]
  return {
    ...condition,
    columnId: def.id,
    operator: operatorsForDef(def)[0],
    value: null,
  }
}

export function withOperator(
  condition: FilterCondition,
  operator: FilterOperator,
): FilterCondition {
  return { ...condition, operator, value: null }
}

export function withValue(
  condition: FilterCondition,
  value: FilterValue,
): FilterCondition {
  return { ...condition, value }
}

// ─── Filter v2: group model + tree evaluation ────────────────────────────────

export function isConditionComplete(condition: FilterCondition): boolean {
  return !isEmpty(condition.value)
}

export function evaluateGroup(group: FilterGroup, get: (columnId: string) => unknown): boolean {
  const active = group.conditions.filter(isConditionComplete)
  if (active.length === 0) return true
  const results = active.map((c) => evaluateCondition(get(c.columnId), c.operator, c.value))
  return group.combinator === "and" ? results.every(Boolean) : results.some(Boolean)
}

export function evaluateFilterState(state: FilterState, get: (columnId: string) => unknown): boolean {
  const active = state.groups.filter((g) => g.conditions.some(isConditionComplete))
  if (active.length === 0) return true
  const results = active.map((g) => evaluateGroup(g, get))
  return state.combinator === "and" ? results.every(Boolean) : results.some(Boolean)
}

export function countActiveConditions(state: FilterState): number {
  return state.groups.reduce((sum, g) => sum + g.conditions.filter(isConditionComplete).length, 0)
}

export function emptyFilterState(): FilterState {
  return { combinator: "and", groups: [] }
}

export function newGroup(id: string, conditionId: string, filterDefs: FilterDef[]): FilterGroup {
  return { id, combinator: "and", conditions: [createCondition(filterDefs, conditionId)] }
}

export function addGroup(state: FilterState, groupId: string, conditionId: string, filterDefs: FilterDef[]): FilterState {
  return { ...state, groups: [...state.groups, newGroup(groupId, conditionId, filterDefs)] }
}

function mapGroup(state: FilterState, groupId: string, fn: (g: FilterGroup) => FilterGroup): FilterState {
  return { ...state, groups: state.groups.map((g) => (g.id === groupId ? fn(g) : g)) }
}

export function addConditionToGroup(state: FilterState, groupId: string, condition: FilterCondition): FilterState {
  return mapGroup(state, groupId, (g) => ({ ...g, conditions: [...g.conditions, condition] }))
}

export function updateConditionInGroup(state: FilterState, groupId: string, condition: FilterCondition): FilterState {
  return mapGroup(state, groupId, (g) => ({ ...g, conditions: g.conditions.map((c) => (c.id === condition.id ? condition : c)) }))
}

/**
 * Removes a single condition from a group. If the group becomes empty it is
 * dropped from the state entirely. Use `removeGroup` to remove a group explicitly
 * regardless of its condition count.
 */
export function removeConditionFromGroup(state: FilterState, groupId: string, conditionId: string): FilterState {
  const next = mapGroup(state, groupId, (g) => ({ ...g, conditions: g.conditions.filter((c) => c.id !== conditionId) }))
  return { ...next, groups: next.groups.filter((g) => g.conditions.length > 0) }
}

export function removeGroup(state: FilterState, groupId: string): FilterState {
  return { ...state, groups: state.groups.filter((g) => g.id !== groupId) }
}

export function setGroupCombinator(state: FilterState, groupId: string, combinator: Combinator): FilterState {
  return mapGroup(state, groupId, (g) => ({ ...g, combinator }))
}

export function setTopCombinator(state: FilterState, combinator: Combinator): FilterState {
  return { ...state, combinator }
}

export function normalizeFilterState(state: FilterState, filterableIds: string[]): FilterState {
  const allowed = new Set(filterableIds)
  const groups = state.groups
    .map((g) => ({ ...g, conditions: g.conditions.filter((c) => allowed.has(c.columnId)) }))
    .filter((g) => g.conditions.length > 0)
  return { ...state, groups }
}

"use client"

import * as React from "react"
import {
  getCoreRowModel,
  getExpandedRowModel,
  getGroupedRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
  type ColumnDef,
  type ExpandedState,
  type GroupingState,
  type PaginationState,
  type SortingState,
  type Table,
} from "@tanstack/react-table"

import {
  deriveColumnVisibility,
  normalizeGrouping,
} from "./grouping-utils"
import {
  evaluateFilterState,
  normalizeFilterState,
  emptyFilterState,
} from "./filter-utils"
import type { FilterState } from "./types"
import { GROUP_COLUMN_ID, type FilterDef, type GroupedDataTableProps } from "./types"

// Stable empty default so omitting `filterableColumns` doesn't create a new
// array reference each render (which would churn the derived memos/callbacks).
const EMPTY_FILTER_COLUMNS: FilterDef[] = []

export type UseGroupedTableResult<TData> = {
  table: Table<TData>
  grouping: GroupingState
  setGrouping: (next: GroupingState) => void
  filterState: FilterState
  setFilterState: (next: FilterState | ((prev: FilterState) => FilterState)) => void
}

export function useGroupedTable<TData>({
  data,
  columns,
  groupableDimensions,
  groupColumn,
  initialGrouping = [],
  enablePagination = true,
  filterableColumns = EMPTY_FILTER_COLUMNS,
  initialFilterState,
}: GroupedDataTableProps<TData>): UseGroupedTableResult<TData> {
  const allowedIds = React.useMemo(
    () => groupableDimensions.map((d) => d.id),
    [groupableDimensions],
  )

  const [grouping, setGroupingState] = React.useState<GroupingState>(() =>
    normalizeGrouping(initialGrouping, allowedIds),
  )
  const [expanded, setExpanded] = React.useState<ExpandedState>({})
  const [sorting, setSorting] = React.useState<SortingState>([])
  const [pagination, setPagination] = React.useState<PaginationState>({
    pageIndex: 0,
    pageSize: 50,
  })

  const filterableIds = React.useMemo(
    () => filterableColumns.map((f) => f.id),
    [filterableColumns],
  )

  const [filterState, setFilterStateRaw] = React.useState<FilterState>(() =>
    normalizeFilterState(initialFilterState ?? emptyFilterState(), filterableIds),
  )

  const setFilterState = React.useCallback(
    (next: FilterState | ((prev: FilterState) => FilterState)) => {
      setFilterStateRaw((prev) =>
        normalizeFilterState(typeof next === "function" ? next(prev) : next, filterableIds),
      )
    },
    [filterableIds],
  )

  // Pre-filter rows against the FilterState tree, then hand the result to
  // TanStack (so grouping/aggregation/counts recompute over filtered rows).
  // Values are read by accessorKey via `row[columnId]` — see FilterDef.id.
  const filteredData = React.useMemo(() => {
    if (filterState.groups.length === 0) return data
    return data.filter((row) =>
      evaluateFilterState(filterState, (columnId) => (row as Record<string, unknown>)[columnId]),
    )
  }, [data, filterState])

  // setGrouping that always normalizes against allowed dimensions.
  const setGrouping = React.useCallback(
    (next: GroupingState) => {
      setGroupingState(normalizeGrouping(next, allowedIds))
    },
    [allowedIds],
  )

  // Synthesized auto group column. The actual cell rendering is handled by
  // <GroupCell> in the table body; here we only reserve the slot. The def only
  // reads `groupColumn.header`, so memoize on that alone — depending on the whole
  // `groupColumn` object would rebuild the column array whenever a consumer passes
  // an inline config literal (e.g. `groupColumn={{ renderLeaf: ... }}`).
  const groupColumnDef = React.useMemo<ColumnDef<TData, unknown>>(
    () => ({
      id: GROUP_COLUMN_ID,
      header: () => groupColumn.header ?? null,
      enableGrouping: false,
      cell: () => null,
    }),
    [groupColumn.header],
  )

  const allColumns = React.useMemo(
    () => [groupColumnDef, ...columns],
    [groupColumnDef, columns],
  )

  // `columnVisibility` is fully derived from `grouping`: grouped dimension columns
  // are hidden so their values appear only in the auto group column. This is
  // intentionally one-way — no `onColumnVisibilityChange` is wired, so consumer
  // calls to `table.toggleVisibility()` would be overridden on the next render. If
  // user-toggled visibility is ever needed, merge it here:
  // `{ ...userVisibility, ...deriveColumnVisibility(grouping) }`.
  const columnVisibility = React.useMemo(
    () => deriveColumnVisibility(grouping),
    [grouping],
  )

  // React Compiler reports "Use of incompatible library" here: useReactTable
  // returns identity-stable functions it cannot safely memoize, so it skips
  // compiling this component. This is expected with TanStack Table and is
  // harmless — the table manages its own memoization internally.
  const table = useReactTable<TData>({
    data: filteredData,
    columns: allColumns,
    state: {
      grouping,
      expanded,
      sorting,
      columnVisibility,
      ...(enablePagination ? { pagination } : {}),
    },
    onGroupingChange: (updater) => {
      const next =
        typeof updater === "function" ? updater(grouping) : updater
      setGrouping(next)
    },
    onExpandedChange: setExpanded,
    onSortingChange: setSorting,
    onPaginationChange: setPagination,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getGroupedRowModel: getGroupedRowModel(),
    getExpandedRowModel: getExpandedRowModel(),
    ...(enablePagination
      ? { getPaginationRowModel: getPaginationRowModel() }
      : {}),
    paginateExpandedRows: false,
    autoResetExpanded: false,
    // Don't bounce the user back to page 1 when filters/grouping/sorting change.
    autoResetPageIndex: false,
  })

  // autoResetPageIndex: false keeps the user's page, but TanStack never
  // clamps: grouping routinely collapses 120 leaf rows into a handful of
  // groups, so a user sitting on page 3 who then groups by a 4-value
  // dimension would get rows.slice(100, 150) of a 4-row model — an empty
  // table rendering "No results." + "Page 3 of 1". Snap back to the last
  // real page instead. pageCount is 0 for an empty result set (nothing to
  // snap to), hence the > 0 guard.
  const pageCount = table.getPageCount()
  const pageIndex = table.getState().pagination.pageIndex
  React.useEffect(() => {
    if (enablePagination && pageCount > 0 && pageIndex > pageCount - 1) {
      table.setPageIndex(pageCount - 1)
    }
  }, [enablePagination, pageCount, pageIndex, table])

  return { table, grouping, setGrouping, filterState, setFilterState }
}

"use client"

// Radix build of the primitives shim. Keep the EXPORTED API identical to its
// base-ui twin, primitives.tsx — only the function bodies may differ. The
// divergences between the two files are exactly:
//   1. <Select> omits the `items` prop here; the base-ui build requires it.
//   2. Radix `onValueChange` is `(value: string) => void` (non-nullable), so no
//      guard here; the base-ui build guards `v != null`.
//   3. PopoverButtonTrigger composes via `asChild` + a nested <Button> here; the
//      base-ui build uses base-ui's `render` prop.
// This file is distribution-only: it is excluded from this repo's typecheck
// (tsconfig `**/*.radix.tsx`) and is never imported here — it is validated
// against real Radix primitives in a consumer project.

import * as React from "react"

import { Button } from "@/components/ui/button"
import { PopoverTrigger } from "@/components/ui/popover"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

export type SelectOption = { value: string; label: string }

export type FieldSelectProps = {
  value: string
  items: SelectOption[]
  onValueChange: (value: string) => void
  ariaLabel: string
  placeholder?: string
  size?: "sm" | "default"
  className?: string
}

/** Radix build of the FieldSelect shim — see primitives.tsx for the base-ui build. */
export function FieldSelect({
  value,
  items,
  onValueChange,
  ariaLabel,
  placeholder,
  size = "sm",
  className,
}: FieldSelectProps) {
  return (
    <Select value={value} onValueChange={(v) => onValueChange(String(v))}>
      <SelectTrigger aria-label={ariaLabel} size={size} className={className}>
        <SelectValue placeholder={placeholder} />
      </SelectTrigger>
      <SelectContent>
        {items.map((item) => (
          <SelectItem key={item.value} value={item.value}>
            {item.label}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  )
}

export type PopoverButtonTriggerProps = {
  children: React.ReactNode
  variant?: React.ComponentProps<typeof Button>["variant"]
  size?: React.ComponentProps<typeof Button>["size"]
  className?: string
  ariaLabel?: string
  disabled?: boolean
}

/** Radix build of the PopoverButtonTrigger shim — see primitives.tsx for the base-ui build. */
export function PopoverButtonTrigger({
  children,
  variant = "outline",
  size = "sm",
  className,
  ariaLabel,
  disabled,
}: PopoverButtonTriggerProps) {
  return (
    <PopoverTrigger asChild>
      <Button
        type="button"
        variant={variant}
        size={size}
        aria-label={ariaLabel}
        className={className}
        disabled={disabled}
      >
        {children}
      </Button>
    </PopoverTrigger>
  )
}

"use client"

import { ChevronDown } from "lucide-react"

import { cn } from "@/lib/utils"
import { Checkbox } from "@/components/ui/checkbox"
import { Popover, PopoverContent } from "@/components/ui/popover"

import { PopoverButtonTrigger } from "./primitives"

export type MultiSelectOption = { label: string; value: string }

type MultiSelectProps = {
  options: MultiSelectOption[]
  selected: string[]
  onChange: (next: string[]) => void
  placeholder?: string
  /**
   * Accessible label for the trigger button. Pass this whenever the visible
   * label ("N selected") doesn't convey what is being selected (the common case).
   */
  ariaLabel?: string
  className?: string
}

export function multiSelectLabel(selected: string[], placeholder: string): string {
  return selected.length === 0 ? placeholder : `${selected.length} selected`
}

export function MultiSelectContent({
  options,
  selected,
  onChange,
}: Pick<MultiSelectProps, "options" | "selected" | "onChange">) {
  // Controlled: each checkbox reflects `selected`, so duplicate-adds can't occur
  // as long as the caller feeds the updated `selected` back before the next click.
  function toggle(value: string, checked: boolean) {
    onChange(checked ? [...selected, value] : selected.filter((v) => v !== value))
  }
  return (
    <div className="flex max-h-64 flex-col gap-1 overflow-auto">
      {options.map((opt) => (
        <label
          key={opt.value}
          className="flex cursor-pointer items-center gap-2 rounded-sm px-1 py-1 text-sm select-none hover:bg-muted"
        >
          <Checkbox
            checked={selected.includes(opt.value)}
            onCheckedChange={(checked) => toggle(opt.value, checked === true)}
          />
          {opt.label}
        </label>
      ))}
    </div>
  )
}

export function MultiSelect({
